import React from "react";
import {
    Accordion,
    AccordionContent,
    AccordionItem,
    AccordionTrigger,
} from "../components/ui/accordion";
import { FAQS } from "../data/content";

export default function FAQ() {
    return (
        <section
            id="faq"
            data-testid="faq-section"
            className="section-pad bg-[#F7FAFF]"
        >
            <div className="container-x grid lg:grid-cols-12 gap-12">
                <div className="lg:col-span-4">
                    <span className="text-xs font-semibold uppercase tracking-[0.18em] text-[#0A5BFF]">
                        FAQ
                    </span>
                    <h2 className="font-display text-3xl md:text-4xl lg:text-5xl mt-3 text-[#041C4A] leading-tight">
                        Questions, <br />
                        <span className="gradient-text">answered.</span>
                    </h2>
                    <p className="mt-5 text-[#4B5A78] max-w-sm">
                        Can&apos;t find what you&apos;re looking for? Our team replies in
                        minutes on WhatsApp.
                    </p>
                </div>

                <div className="lg:col-span-8">
                    <Accordion type="single" collapsible className="space-y-3">
                        {FAQS.map((f, i) => (
                            <AccordionItem
                                key={i}
                                value={`item-${i}`}
                                data-testid={`faq-item-${i}`}
                                className="bg-white border border-[#E2E8F0] rounded-2xl px-5 md:px-6 shadow-soft data-[state=open]:border-[#0A5BFF]/30"
                            >
                                <AccordionTrigger className="text-left font-display text-base md:text-lg text-[#041C4A] hover:no-underline py-5">
                                    {f.q}
                                </AccordionTrigger>
                                <AccordionContent className="text-[#4B5A78] text-sm md:text-base leading-relaxed pb-5">
                                    {f.a}
                                </AccordionContent>
                            </AccordionItem>
                        ))}
                    </Accordion>
                </div>
            </div>
        </section>
    );
}
